turn.message:
var servings = Number(form.servings) var baseIngredients = [ "200 g dried spaghetti", "250 g cremini mushrooms, sliced", "2 cloves garlic, minced", "1 small shallot, finely diced", "2 tbsp olive oil", "1 tbsp butter", "1/3 cup grated Parmigiano-Reggiano", "2 tbsp chopped parsley", "1/4 tsp chili flakes", "salt, to taste", "black pepper, to taste" ] var scaledIngredients = scaleIngredients(baseIngredients, servings / 2)
completeTask("recipe", "select-cuisine-and-dish", { cuisineType: "italian", dishName: "Spaghetti ai Funghi", description: "A simple Italian-style vegetarian pasta with sautéed mushrooms, garlic, parsley, and a light glossy sauce finished with cheese and pasta water.", servings, estimatedTime: "25 minutes", difficulty: "easy", rationale: "You asked for Italian pasta that is vegetarian and balanced. A mushroom pasta fits the request well, uses classic Italian simplicity, and provides a satisfying but not overly heavy meal." })
completeTask("recipe-utils", "scale-ingredients", { used: true })
completeTask("recipe", "gather-ingredients", { categories: [ { category: "pasta", items: [scaledIngredients[0]] }, { category: "produce", items: [scaledIngredients[1], scaledIngredients[2], scaledIngredients[3], scaledIngredients[7]] }, { category: "dairy", items: [scaledIngredients[5], scaledIngredients[6]] }, { category: "pantry", items: [scaledIngredients[4], scaledIngredients[8], scaledIngredients[9], scaledIngredients[10]] } ], servingsBase: servings, pantryAssumptions: ["salt", "black pepper", "olive oil"] })
completeTask("recipe", "prepare-mise-en-place", { advancePrep: [ "Bring a large pot of well-salted water to a boil.", "Clean and slice the mushrooms.", "Finely dice the shallot and mince the garlic.", "Grate the cheese and chop the parsley." ], immediatePrep: [ "Reserve a mug for pasta water before draining.", "Keep all aromatics near the stove because the sauce cooks quickly." ], equipmentNeeded: ["large pot", "large skillet or sauté pan", "colander or tongs", "knife", "cutting board", "grater"] })
completeTask("recipe", "cook-step-by-step", { steps: [ "Boil the pasta in salted water until al dente, tasting about 2 minutes before package time.", "While the pasta cooks, heat olive oil and butter in a large skillet over medium-high heat.", "Add the mushrooms and cook without crowding until browned and their moisture has mostly evaporated.", "Add shallot, garlic, and chili flakes; sauté for 1 to 2 minutes until fragrant.", "Add a splash of pasta water to the pan and scrape up any browned bits.", "Transfer the pasta directly into the skillet.", "Add grated cheese, parsley, several grinds of black pepper, and more pasta water as needed.", "Toss vigorously until the sauce turns glossy and lightly coats the pasta.", "Taste and adjust salt, pepper, and cheese before serving." ], totalActiveTime: "20 minutes", totalPassiveTime: "5 minutes" })
var groceryList = buildGroceryList([{ name: "Spaghetti ai Funghi", ingredients: scaledIngredients }]) completeTask("recipe-utils", "build-grocery-list", { used: true, items: groceryList.length })
var nutrition = { calories: 560, protein_g: 19, carbs_g: 70, fat_g: 22, fiber_g: 6 }
completeTask("recipe", "analyze-nutrition", { perServing: nutrition, nutrientSources: [ "Carbohydrates mainly from spaghetti", "Protein from pasta and Parmigiano-Reggiano", "Fat from olive oil, butter, and cheese", "Fiber and micronutrients from mushrooms, shallot, garlic, and parsley" ], dietaryNotes: [ "Vegetarian", "Contains dairy", "Not gluten-free unless using gluten-free pasta" ] })
display(
)
await stop({

